import React, { useState, useRef, useEffect } from 'react';
import './AIAssistant.css';

const API_KEY = process.env.REACT_APP_GEMINI_API_KEY;
const SYSTEM_CONTEXT = `You are EduAdmit AI, a helpful college admissions assistant for a college admission portal. 
You help students with:
- Course selection advice (B.Tech IT, B.Tech CSE, BBA and other programs)
- Admission process guidance (registration, application, documents, payment)
- Document requirements (marksheets, ID proof, etc.)
- Application status understanding
- Career advice related to courses
- General college admission tips

Keep responses concise, friendly and helpful. Use bullet points for lists. 
If asked about specific personal information (passwords, etc.) politely decline.
Always encourage students to use the platform to apply.`;

const SUGGESTIONS = [
  'Which course is best for a software career?',
  'What documents do I need to apply?',
  'How long does admission take?',
  'What is the application fee?',
  'Tell me about B.Tech CSE',
  'How to check my application status?',
];

function AIAssistant() {
  const [messages, setMessages] = useState([
    {
      role: 'assistant',
      content: "Hello! 👋 I'm EduAdmit AI, your personal college admissions assistant powered by Google Gemini. I'm here to help you with course selection, application process, document requirements, and more. What can I help you with today?",
      time: new Date()
    }
  ]);
  const [input, setInput] = useState('');
  const [loading, setLoading] = useState(false);
  const bottomRef = useRef(null);

  useEffect(() => {
    bottomRef.current?.scrollIntoView({ behavior: 'smooth' });
  }, [messages]);

  const sendMessage = async (text) => {
    const userMsg = text || input.trim();
    if (!userMsg) return;
    setInput('');
    setMessages(prev => [...prev, { role: 'user', content: userMsg, time: new Date() }]);
    setLoading(true);

    try {
      if (!API_KEY || API_KEY === 'your_gemini_api_key_here') {
        // Demo mode without API key
        await new Promise(r => setTimeout(r, 1200));
        const demoResponses = {
          'course': '**B.Tech CSE** is ideal for software engineering careers, covering algorithms, data structures, and AI. **B.Tech IT** focuses on practical systems, networking, and enterprise software. **BBA** is perfect for management and entrepreneurship. What are your career interests?',
          'document': 'For admission, you\'ll need:\n• 10th & 12th Marksheets\n• Government ID (Aadhaar/Passport)\n• Passport-size photographs\n• Transfer Certificate (if applicable)\n• Character Certificate',
          'fee': 'The application fee is **₹500**, payable via UPI, Credit/Debit Card, or Net Banking. This is a one-time, non-refundable fee.',
          'status': 'You can track your application from the **Dashboard** → **My Status** section. You\'ll see a timeline showing: Submitted → Under Review → Decision → Enrolled.',
          'default': 'Great question! I\'m here to help with your college admissions journey. Please register on EduAdmit to start your application. Our officers review applications within 5-7 business days. Is there anything specific about the admission process I can clarify?'
        };
        const key = Object.keys(demoResponses).find(k => userMsg.toLowerCase().includes(k));
        setMessages(prev => [...prev, { role: 'assistant', content: demoResponses[key] || demoResponses.default, time: new Date() }]);
        setLoading(false);
        return;
      }

      const history = messages.slice(-10).map(m => ({
        role: m.role === 'assistant' ? 'model' : 'user',
        parts: [{ text: m.content }]
      }));

      const response = await fetch(
        `https://generativelanguage.googleapis.com/v1beta/models/gemini-2.0-flash:generateContent?key=${API_KEY}`,
        {
          method: 'POST',
          headers: { 'Content-Type': 'application/json' },
          body: JSON.stringify({
            contents: [
              { role: 'user', parts: [{ text: SYSTEM_CONTEXT }] },
              { role: 'model', parts: [{ text: 'Understood! I am EduAdmit AI, ready to help.' }] },
              ...history,
              { role: 'user', parts: [{ text: userMsg }] }
            ],
            generationConfig: { maxOutputTokens: 500, temperature: 0.7 }
          })
        }
      );

      const data = await response.json();
      const reply = data.candidates?.[0]?.content?.parts?.[0]?.text || 'Sorry, I could not process that. Please try again.';
      setMessages(prev => [...prev, { role: 'assistant', content: reply, time: new Date() }]);
    } catch {
      setMessages(prev => [...prev, {
        role: 'assistant',
        content: '⚠️ I\'m having trouble connecting right now. Please check your internet connection or API key configuration in .env file.',
        time: new Date()
      }]);
    } finally { setLoading(false); }
  };

  const formatMessage = (content) => {
    return content
      .replace(/\*\*(.*?)\*\*/g, '<strong>$1</strong>')
      .replace(/\*(.*?)\*/g, '<em>$1</em>')
      .replace(/•\s/g, '• ')
      .replace(/\n/g, '<br/>');
  };

  const formatTime = (date) => date.toLocaleTimeString([], { hour: '2-digit', minute: '2-digit' });

  return (
    <div className="ai-page page-wrapper">
      <div className="ai-layout">
        {/* Sidebar */}
        <div className="ai-sidebar">
          <div className="ais-header">
            <div className="ais-logo">🤖</div>
            <h3>EduAdmit AI</h3>
            <p>Powered by Google Gemini</p>
          </div>
          <div className="ais-suggestions">
            <div className="ais-section-title">Quick Questions</div>
            {SUGGESTIONS.map((s, i) => (
              <button key={i} className="ais-suggestion" onClick={() => sendMessage(s)}>
                {s}
              </button>
            ))}
          </div>
          <div className="ais-capabilities">
            <div className="ais-section-title">I Can Help With</div>
            <div className="ais-cap">🎓 Course Selection</div>
            <div className="ais-cap">📋 Admission Process</div>
            <div className="ais-cap">📁 Documents Required</div>
            <div className="ais-cap">💳 Fee Information</div>
            <div className="ais-cap">📊 Application Tracking</div>
            <div className="ais-cap">🚀 Career Guidance</div>
          </div>
        </div>

        {/* Chat Area */}
        <div className="ai-chat-area">
          <div className="aca-header">
            <div className="aca-bot">
              <div className="aca-bot-icon">🤖</div>
              <div>
                <div className="aca-bot-name">EduAdmit AI Assistant</div>
                <div className="aca-bot-status">● Online — Ready to help</div>
              </div>
            </div>
            <button className="aca-clear" onClick={() => setMessages([messages[0]])}>Clear Chat</button>
          </div>

          {/* Messages */}
          <div className="aca-messages">
            {messages.map((msg, i) => (
              <div key={i} className={`message ${msg.role}`}>
                {msg.role === 'assistant' && <div className="msg-avatar">🤖</div>}
                <div className="msg-content">
                  <div
                    className="msg-bubble"
                    dangerouslySetInnerHTML={{ __html: formatMessage(msg.content) }}
                  />
                  <div className="msg-time">{formatTime(msg.time)}</div>
                </div>
                {msg.role === 'user' && <div className="msg-user-avatar">👤</div>}
              </div>
            ))}
            {loading && (
              <div className="message assistant">
                <div className="msg-avatar">🤖</div>
                <div className="msg-content">
                  <div className="msg-bubble typing">
                    <div className="typing-dots">
                      <span></span><span></span><span></span>
                    </div>
                  </div>
                </div>
              </div>
            )}
            <div ref={bottomRef} />
          </div>

          {/* Input */}
          <div className="aca-input-area">
            <div className="aca-input-row">
              <input
                type="text"
                className="aca-input"
                placeholder="Ask me anything about college admissions..."
                value={input}
                onChange={e => setInput(e.target.value)}
                onKeyDown={e => e.key === 'Enter' && !loading && sendMessage()}
                disabled={loading}
              />
              <button
                className="aca-send"
                onClick={() => sendMessage()}
                disabled={loading || !input.trim()}
              >
                {loading ? '⏳' : '➤'}
              </button>
            </div>
            <p className="aca-disclaimer">
              AI responses are for guidance only. For official information, contact admissions office.
            </p>
          </div>
        </div>
      </div>
    </div>
  );
}

export default AIAssistant;
